module comparator_64bit (  
    input [63:0] a,  
    input [63:0] b,  
    output reg lesser,  
    output reg equal,  
    output reg less  
);  
    always @(*) begin  
        if (a > b) begin  
            lesser = 1;  
            equal = 0;  
            less = 0;  
        end else if (a < b) begin  
            lesser = 0;  
            equal = 0;  
            less = 1;  
        end else begin  
            lesser = 0;  
            equal = 1;  
            less = 0;  
        end  
    end  
endmodule
